import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';
import { RouterModule } from '@angular/router';          // ✅ fixes router-outlet error

import { AccountRoutingModule } from './account-routing.module';
import { LoginComponent } from './login.component';      // ✅ correct import
import { RegisterComponent } from './register.component';

@NgModule({
  imports: [
    CommonModule,
    ReactiveFormsModule,
    RouterModule,                                         // ✅ needed for router-outlet
    AccountRoutingModule,
    LoginComponent,                                       // ✅ standalone components go in imports
    RegisterComponent
  ]
})
export class AccountModule { }
